#include <unordered_map>
#include <string>
#include <algorithm>
#include <iostream>

string frequencySort(string s) {
    unordered_map<char, int> charFrequency;
    for (char c : s) {
        ++charFrequency[c];
    }

    string result;
    for (char c : s) {
        result += charFrequency[c] > 1 ? c : '';
        charFrequency[c]--;
    }

    return result;
}
```

